const e=JSON.parse('{"key":"v-01b5c7a5","path":"/zh/language/english/daily-english/04-writing.html","title":"写作","lang":"zh-CN","frontmatter":{"icon":"pen","title":"写作","index":true,"article":false,"description":"提示 每日的写作练习，不需要我们在中间使用特别高级的表达，也不需要我们写一篇完整的作文。但是，我们必须在练习中带有自己对于某事物的观点和看法，并且尝试在最后进行润色。这样，我们在真正写作的时候，只要有了好的想法，就能很轻松地写出属于自己的表达。 通常来说，我们可以选一些符合自己观点的中文句子，进行翻译和润色。 我选择先从《顾家北写作》中的 100 个翻译句子练习开始，后面慢慢提升难度。 2022-12-17","head":[["meta",{"property":"og:url","content":"https://zzxzzk115.github.io/blog/zh/language/english/daily-english/04-writing.html"}],["meta",{"property":"og:site_name","content":"Lazy_V 的博客"}],["meta",{"property":"og:title","content":"写作"}],["meta",{"property":"og:description","content":"提示 每日的写作练习，不需要我们在中间使用特别高级的表达，也不需要我们写一篇完整的作文。但是，我们必须在练习中带有自己对于某事物的观点和看法，并且尝试在最后进行润色。这样，我们在真正写作的时候，只要有了好的想法，就能很轻松地写出属于自己的表达。 通常来说，我们可以选一些符合自己观点的中文句子，进行翻译和润色。 我选择先从《顾家北写作》中的 100 个翻译句子练习开始，后面慢慢提升难度。 2022-12-17"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:updated_time","content":"2022-12-19T14:57:12.000Z"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:locale:alternate","content":"en-US"}],["meta",{"property":"article:modified_time","content":"2022-12-19T14:57:12.000Z"}],["link",{"rel":"alternate","hreflang":"en-us","href":"https://zzxzzk115.github.io/blog/language/english/daily-english/04-writing.html"}]]},"headers":[{"level":2,"title":"2022-12-17","slug":"_2022-12-17","link":"#_2022-12-17","children":[{"level":3,"title":"1. 经常做运动会提高人的自信","slug":"_1-经常做运动会提高人的自信","link":"#_1-经常做运动会提高人的自信","children":[]},{"level":3,"title":"2. 教学质量对学生成绩有很大影响","slug":"_2-教学质量对学生成绩有很大影响","link":"#_2-教学质量对学生成绩有很大影响","children":[]}]},{"level":2,"title":"2022-12-19","slug":"_2022-12-19","link":"#_2022-12-19","children":[{"level":3,"title":"3. 家长和老师应该努力去减少小孩看电视的时间","slug":"_3-家长和老师应该努力去减少小孩看电视的时间","link":"#_3-家长和老师应该努力去减少小孩看电视的时间","children":[]},{"level":3,"title":"4. 经济的下滑导致失业率的上升","slug":"_4-经济的下滑导致失业率的上升","link":"#_4-经济的下滑导致失业率的上升","children":[]}]}],"git":{"createdTime":1671205100000,"updatedTime":1671461832000,"contributors":[{"name":"Lazy_V","email":"954294627@qq.com","commits":5}]},"readingTime":{"minutes":1.24,"words":373},"filePathRelative":"zh/language/english/daily-english/04-writing.md","localizedDate":"2022年12月16日","excerpt":"<div class=\\"custom-container tip\\">\\n<p class=\\"custom-container-title\\">提示</p>\\n<p>每日的写作练习，不需要我们在中间使用特别高级的表达，也不需要我们写一篇完整的作文。但是，我们必须在练习中带有自己对于某事物的观点和看法，并且尝试在最后进行润色。这样，我们在真正写作的时候，只要有了好的想法，就能很轻松地写出属于自己的表达。</p>\\n<p>通常来说，我们可以选一些符合自己观点的中文句子，进行翻译和润色。</p>\\n<p>我选择先从《顾家北写作》中的 100 个翻译句子练习开始，后面慢慢提升难度。</p>\\n</div>\\n<h2> 2022-12-17</h2>","autoDesc":true}');export{e as data};
